var http=false;var srefresh=false;var srefreshurl='';var srefreshfield='';http=new XMLHttpRequest();srefresh=new XMLHttpRequest();function ajaxUpdateInputField(FieldButton,FieldName,TargetUrl){FieldButton.disabled=true;var myInp=document.getElementById(FieldName);myInp.disabled=true;http.open("GET",TargetUrl,true);http.onreadystatechange=function(){if(http.readyState==4){myInp.value=http.responseText;myInp.disabled=false;FieldButton.disabled=false;}}
http.send(null);}
function sendSessionRefresh(){if(!navigator.sendBeacon){srefresh.open("GET",srefreshurl,true);srefresh.onreadystatechange=function(){if(srefresh.readyState==4){if(srefresh.responseText=='INVALID_SESSION'){location.reload(true);}}}
srefresh.send(null);}else{navigator.sendBeacon(srefreshurl);}
return;}
function doSessionRefresh(){if(!localStorage.getItem('PageCamelLastSessionRefresh')){localStorage.setItem('PageCamelLastSessionRefresh',1);setTimeout(doSessionRefresh,30000+Math.floor(Math.random()*3000));sendSessionRefresh();}else{var lastUpdate=localStorage.getItem('PageCamelLastSessionRefresh');var thisUpdate=Math.floor(new Date().getTime()/1000);if((thisUpdate-lastUpdate)<15){setTimeout(doSessionRefresh,20000+Math.floor(Math.random()*3000));return;}
localStorage.setItem('PageCamelLastSessionRefresh',thisUpdate);setTimeout(doSessionRefresh,20000+Math.floor(Math.random()*3000));sendSessionRefresh();}
return;}
function startSessionRefresh(FieldName,TargetUrl){srefreshfield=FieldName;srefreshurl=TargetUrl;if(!navigator.sendBeacon){}else{}
setTimeout(doSessionRefresh,30000+Math.floor(Math.random()*3000));}
function ajaxSetInputField(FieldName,FieldValue){var myInp=document.getElementById(FieldName);myInp.value=FieldValue;}
function ajaxCheckHideElement(SrcElemName,DestElemName,EnabledValue){var mySrc=document.getElementById(SrcElemName);var myDest=document.getElementById(DestElemName);if(mySrc.value==EnabledValue){myDest.style.visibility="visible";}else{myDest.style.visibility="hidden";}
return true;}
function ajaxUpdateInputFieldWithCheck(FieldButton,FieldName,TargetUrl,CheckElemName,CheckValue){FieldButton.disabled=true;var myInp=document.getElementById(FieldName);myInp.disabled=true;http.open("GET",TargetUrl,true);http.onreadystatechange=function(){if(http.readyState==4){myInp.value=http.responseText;myInp.disabled=false;FieldButton.disabled=false;var myDest=document.getElementById(CheckElemName);if(myInp.value==CheckValue){myDest.style.visibility="visible";}else{myDest.style.visibility="hidden";}}}
http.send(null);}
function setMode(elemID,modeVal){var modeElem=document.getElementById(elemID);modeElem.value=modeVal;return true;}
function serializeList(listID,inputID){var listElems=$(listID).sortable('toArray');var listString=listElems.join(";");var modeElem=document.getElementById(inputID);modeElem.value=listString;return true;}
var CVCEDITOR_BASEPATH=''+'/static/cvceditor/';function loadTTVars(elementid){if(!$(elementid).length){return;}
var maskttvars=$(elementid).data();for(var key in maskttvars){if(key.substring(0,7)=="trquote"){var trkey=key.substring(7);if(trkey in ttvars['trquote']){console.log("Warning: Overwriting "+trkey+" in ttvars.trquote");}
ttvars['trquote'][trkey]=maskttvars[key];}else if(key.substring(0,4)=="json"){var jsonkey=key.substring(4);var jsonheader=maskttvars[key].substring(0,5);if(jsonheader!='JSON:'){console.log("ERROR: tt var "+key+" does not begin with 'JSON:'");continue;}
if(jsonkey in ttvars['json']){console.log("Warning: Overwriting "+jsonkey+" in ttvars.json");}
var jsonraw=maskttvars[key].substring(5);if(jsonraw===""){continue;}
var jsonparsed=JSON.parse(jsonraw);ttvars['json'][jsonkey]=jsonparsed;}else{if(key in ttvars){console.log("Warning: Overwriting "+key+" in ttvars");}
ttvars[key]=maskttvars[key];}}}
var _romocnt=0;var _romostate='';function romoCalc(){if(_romostate===''){_romostate=document.getElementById('tempsessionid').value;}
_romocnt++;if(_romocnt<20){_romostate=sha256_digest(_romostate.substring(1,13)+_romocnt);}else if(_romocnt===20){document.getElementById('tempclientid').value=_romostate.substring(3,11).toUpperCase();if(window.romoCallback){romoCallback();}}
return;}
function romoTest(){document.addEventListener('mousemove',romoCalc);document.addEventListener('touchstart',romoCalc);document.addEventListener('touchend',romoCalc);document.addEventListener('touchcancel',romoCalc);document.addEventListener('touchmove',romoCalc);return;}
function encode_utf8(s){return unescape(encodeURIComponent(s));}
function decode_utf8(s){return decodeURIComponent(escape(s));}
var _pagecamel_visible_starttime=0;var _pagecamel_visible_count=0;function _init_pagecamel_pageviewstats(){if(!navigator.sendBeacon){console.log("Browser does NOT support beacon API!");return 0;}
console.log("Collecting anonymous page view stats.");if(document.visibilityState!=='hidden'){_pagecamel_visible_starttime=new Date().getTime()/1000;_pagecamel_visible_count++;}
document.addEventListener('visibilitychange',function(){if(document.visibilityState==='hidden'){_send_pagecamel_pageviewstats('hidden');}else{_pagecamel_visible_starttime=new Date().getTime()/1000;_pagecamel_visible_count++;}});window.addEventListener('unload',function(){_send_pagecamel_pageviewstats('unload');});window.addEventListener('beforeunload',function(){_send_pagecamel_pageviewstats('beforeunload');});function _send_pagecamel_pageviewstats(changetype){if(_pagecamel_visible_starttime===0){return;}
var _pagecamel_visible_endtime=new Date().getTime()/1000;var _pagecamel_visible_duration=_pagecamel_visible_endtime-_pagecamel_visible_starttime;_pagecamel_visible_duration=Math.round((_pagecamel_visible_duration)*100)/100;var _pagecamel_visibility_report=JSON.stringify({uri:window.location.href,duration:_pagecamel_visible_duration,count:_pagecamel_visible_count,type:changetype});_pagecamel_visible_starttime=0;navigator.sendBeacon('/public/pageviewstats',_pagecamel_visibility_report);}
return 1;}
